// TDD Test Runner for CSV Report Generator
// Uses a simple assertion framework — no external dependencies needed.
// Each test follows red/green/refactor: tests were written BEFORE the implementation.

#:package Microsoft.CodeAnalysis.CSharp.Scripting@4.12.0

using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;

// ─── Minimal test framework ────────────────────────────────────────────────────

int passed = 0, failed = 0;
var failures = new List<string>();

void Assert(bool condition, string message)
{
    if (condition) { passed++; Console.WriteLine($"  ✓ {message}"); }
    else { failed++; failures.Add(message); Console.WriteLine($"  ✗ {message}"); }
}

void AssertEqual<T>(T expected, T actual, string message)
{
    bool eq = EqualityComparer<T>.Default.Equals(expected, actual);
    if (!eq) message += $" (expected: {expected}, got: {actual})";
    Assert(eq, message);
}

void AssertThrows<TEx>(Action action, string message) where TEx : Exception
{
    try { action(); Assert(false, message + " — no exception thrown"); }
    catch (TEx) { Assert(true, message); }
    catch (Exception ex) { Assert(false, message + $" — wrong exception: {ex.GetType().Name}"); }
}

// ─── Resolve paths relative to this script ──────────────────────────────────────

string baseDir = AppContext.BaseDirectory;
// When running via `dotnet run tests.cs`, the base directory is a temp build folder.
// We need the directory where the script file actually lives.
string scriptDir = Directory.GetCurrentDirectory();

// ─── Load the library under test ────────────────────────────────────────────────
// We compile and load CsvReportLib.cs so we can call its public API directly.

using Microsoft.CodeAnalysis.CSharp.Scripting;
using Microsoft.CodeAnalysis.Scripting;

// Load the library source and evaluate it to get access to the types.
string libSource = File.ReadAllText(Path.Combine(scriptDir, "CsvReportLib.cs"));

// We'll use a different approach: compile the library into an assembly we can reference.
// Since file-based apps don't support project references, we dynamically compile.
var scriptOptions = ScriptOptions.Default
    .AddReferences(typeof(object).Assembly, typeof(Enumerable).Assembly, typeof(File).Assembly)
    .AddImports("System", "System.Collections.Generic", "System.IO", "System.Linq");

// Evaluate the library script — it defines types we can then use via dynamic.
var state = await CSharpScript.RunAsync(libSource, scriptOptions);

// Helper to invoke static methods on CsvReportLib types via the script state
dynamic Invoke(string code) => CSharpScript.RunAsync(code, scriptOptions, globals: null, globalsType: null)
    .ContinueWith(t => t.Result.ReturnValue).Result;

// Actually, a cleaner approach: continue the same script session to call library methods.
async Task<object?> Run(string code)
{
    state = await state.ContinueWithAsync(code);
    return state.ReturnValue;
}

// ─── TEST SUITE ─────────────────────────────────────────────────────────────────

Console.WriteLine("\n═══ CSV Report Generator — Test Suite ═══\n");

// ── 1. CSV Parsing Tests ────────────────────────────────────────────────────────
Console.WriteLine("── CSV Parsing ──");

// Test: Parse a simple CSV string into Employee records
{
    var csv = "name,department,salary,hire_date,status\nAlice,Engineering,90000,2020-01-01,active\n";
    var result = await Run($"""
        CsvParser.Parse(@"{csv.Replace("\"", "\"\"")}").ToList()
    """);
    var list = (System.Collections.IList)result!;
    AssertEqual(1, list.Count, "Parse single row: count = 1");

    // Check fields via dynamic
    dynamic emp = list[0]!;
    AssertEqual("Alice", (string)emp.Name, "Parse single row: name = Alice");
    AssertEqual("Engineering", (string)emp.Department, "Parse single row: department = Engineering");
    AssertEqual(90000m, (decimal)emp.Salary, "Parse single row: salary = 90000");
    AssertEqual("active", (string)emp.Status, "Parse single row: status = active");
}

// Test: Parse multiple rows
{
    var csv = "name,department,salary,hire_date,status\nA,Eng,100000,2020-01-01,active\nB,Sales,80000,2021-06-15,inactive\n";
    var result = await Run($"""
        CsvParser.Parse(@"{csv.Replace("\"", "\"\"")}").ToList()
    """);
    var list = (System.Collections.IList)result!;
    AssertEqual(2, list.Count, "Parse multiple rows: count = 2");
}

// Test: Handle empty input gracefully
{
    var result = await Run("""CsvParser.Parse("name,department,salary,hire_date,status\n").ToList()""");
    var list = (System.Collections.IList)result!;
    AssertEqual(0, list.Count, "Parse empty CSV (header only): count = 0");
}

// Test: Reject invalid salary
{
    try
    {
        await Run("""CsvParser.Parse("name,department,salary,hire_date,status\nA,Eng,notanumber,2020-01-01,active\n").ToList()""");
        Assert(false, "Parse invalid salary: should throw");
    }
    catch
    {
        Assert(true, "Parse invalid salary: throws on bad data");
    }
}

// ── 2. Filtering Tests ──────────────────────────────────────────────────────────
Console.WriteLine("\n── Filtering ──");

// Test: Filter to active employees only
{
    var csv = "name,department,salary,hire_date,status\nA,Eng,100000,2020-01-01,active\nB,Sales,80000,2021-06-15,inactive\nC,Eng,90000,2022-03-10,active\n";
    var result = await Run($"""
        EmployeeFilter.ActiveOnly(CsvParser.Parse(@"{csv.Replace("\"", "\"\"")}")).ToList()
    """);
    var list = (System.Collections.IList)result!;
    AssertEqual(2, list.Count, "ActiveOnly: returns 2 active employees");
    dynamic first = list[0]!;
    AssertEqual("A", (string)first.Name, "ActiveOnly: first active is A");
}

// Test: Filter when all are inactive
{
    var csv = "name,department,salary,hire_date,status\nA,Eng,100000,2020-01-01,inactive\nB,Sales,80000,2021-06-15,inactive\n";
    var result = await Run($"""
        EmployeeFilter.ActiveOnly(CsvParser.Parse(@"{csv.Replace("\"", "\"\"")}")).ToList()
    """);
    var list = (System.Collections.IList)result!;
    AssertEqual(0, list.Count, "ActiveOnly: returns 0 when all inactive");
}

// Test: Case-insensitive status matching
{
    var csv = "name,department,salary,hire_date,status\nA,Eng,100000,2020-01-01,Active\nB,Sales,80000,2021-06-15,ACTIVE\n";
    var result = await Run($"""
        EmployeeFilter.ActiveOnly(CsvParser.Parse(@"{csv.Replace("\"", "\"\"")}")).ToList()
    """);
    var list = (System.Collections.IList)result!;
    AssertEqual(2, list.Count, "ActiveOnly: case-insensitive status matching");
}

// ── 3. Aggregation Tests ────────────────────────────────────────────────────────
Console.WriteLine("\n── Aggregation ──");

// Test: Average salary by department
{
    var csv = "name,department,salary,hire_date,status\nA,Eng,100000,2020-01-01,active\nB,Eng,80000,2021-06-15,active\nC,Sales,60000,2022-03-10,active\n";
    var result = await Run($"""
        Aggregator.AverageSalaryByDepartment(CsvParser.Parse(@"{csv.Replace("\"", "\"\"")}"))
    """);
    var dict = (IDictionary<string, decimal>)result!;
    AssertEqual(90000m, dict["Eng"], "AvgSalary: Eng = 90000");
    AssertEqual(60000m, dict["Sales"], "AvgSalary: Sales = 60000");
}

// Test: Headcount by department
{
    var csv = "name,department,salary,hire_date,status\nA,Eng,100000,2020-01-01,active\nB,Eng,80000,2021-06-15,active\nC,Sales,60000,2022-03-10,active\n";
    var result = await Run($"""
        Aggregator.HeadcountByDepartment(CsvParser.Parse(@"{csv.Replace("\"", "\"\"")}"))
    """);
    var dict = (IDictionary<string, int>)result!;
    AssertEqual(2, dict["Eng"], "Headcount: Eng = 2");
    AssertEqual(1, dict["Sales"], "Headcount: Sales = 1");
}

// Test: Overall statistics
{
    var csv = "name,department,salary,hire_date,status\nA,Eng,100000,2020-01-01,active\nB,Eng,80000,2021-06-15,active\nC,Sales,60000,2022-03-10,active\n";
    var result = await Run($"""
        Aggregator.OverallStats(CsvParser.Parse(@"{csv.Replace("\"", "\"\"")}"))
    """);
    dynamic stats = result!;
    AssertEqual(3, (int)stats.TotalEmployees, "OverallStats: total = 3");
    AssertEqual(80000m, (decimal)stats.AverageSalary, "OverallStats: avg = 80000");
    AssertEqual(60000m, (decimal)stats.MinSalary, "OverallStats: min = 60000");
    AssertEqual(100000m, (decimal)stats.MaxSalary, "OverallStats: max = 100000");
    AssertEqual(240000m, (decimal)stats.TotalPayroll, "OverallStats: payroll = 240000");
}

// ── 4. Report Formatting Tests ──────────────────────────────────────────────────
Console.WriteLine("\n── Report Formatting ──");

// Test: Report contains key sections
{
    var csv = "name,department,salary,hire_date,status\nA,Eng,100000,2020-01-01,active\nB,Sales,60000,2022-03-10,active\n";
    var result = await Run($"""
        ReportFormatter.GenerateReport(CsvParser.Parse(@"{csv.Replace("\"", "\"\"")}"))
    """);
    var report = (string)result!;
    Assert(report.Contains("Department Summary"), "Report contains 'Department Summary'");
    Assert(report.Contains("Overall Statistics"), "Report contains 'Overall Statistics'");
    Assert(report.Contains("Eng"), "Report contains department name 'Eng'");
    Assert(report.Contains("Sales"), "Report contains department name 'Sales'");
    Assert(report.Contains("100,000") || report.Contains("100000"), "Report contains salary figure");
}

// ── 5. File I/O Integration Tests ───────────────────────────────────────────────
Console.WriteLine("\n── File I/O ──");

// Test: Read from actual CSV file
{
    string testCsvPath = Path.Combine(scriptDir, "test_data.csv");
    var result = await Run($"""
        CsvParser.ParseFile(@"{testCsvPath.Replace("\\", "\\\\")}").ToList()
    """);
    var list = (System.Collections.IList)result!;
    AssertEqual(10, list.Count, "ParseFile: reads 10 rows from test_data.csv");
}

// Test: Full pipeline — read CSV, filter, aggregate, write report
{
    string testCsvPath = Path.Combine(scriptDir, "test_data.csv");
    string outputPath = Path.Combine(scriptDir, "test_output_report.txt");
    await Run($"""
        ReportPipeline.Run(@"{testCsvPath.Replace("\\", "\\\\")}", @"{outputPath.Replace("\\", "\\\\")}")
    """);
    Assert(File.Exists(outputPath), "Pipeline: output file created");
    string content = File.ReadAllText(outputPath);
    Assert(content.Contains("Engineering"), "Pipeline: report contains Engineering");
    Assert(content.Contains("Marketing"), "Pipeline: report contains Marketing");
    Assert(content.Contains("Sales"), "Pipeline: report contains Sales");
    Assert(content.Length > 200, "Pipeline: report has substantial content");
    // Cleanup
    File.Delete(outputPath);
}

// Test: Error on missing file
{
    try
    {
        await Run("""CsvParser.ParseFile("/nonexistent/file.csv").ToList()""");
        Assert(false, "ParseFile missing file: should throw");
    }
    catch
    {
        Assert(true, "ParseFile missing file: throws descriptive error");
    }
}

// ── Summary ─────────────────────────────────────────────────────────────────────
Console.WriteLine($"\n═══ Results: {passed} passed, {failed} failed ═══");
if (failures.Count > 0)
{
    Console.WriteLine("\nFailures:");
    foreach (var f in failures) Console.WriteLine($"  ✗ {f}");
}
Environment.ExitCode = failed > 0 ? 1 : 0;

