// TDD Test Runner for CSV Report Generator
// Uses a simple assertion framework — no external dependencies needed.
// Each test follows red/green/refactor: tests were written BEFORE the implementation.

#:package Microsoft.CodeAnalysis.CSharp.Scripting@4.12.0

using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Microsoft.CodeAnalysis.CSharp.Scripting;
using Microsoft.CodeAnalysis.Scripting;

// ─── Minimal test framework ────────────────────────────────────────────────────

int passed = 0, failed = 0;
var failures = new List<string>();

void AssertTrue(bool condition, string message)
{
    if (condition) { passed++; Console.WriteLine($"  ✓ {message}"); }
    else { failed++; failures.Add(message); Console.WriteLine($"  ✗ {message}"); }
}

void AssertEqual<T>(T expected, T actual, string message)
{
    bool eq = EqualityComparer<T>.Default.Equals(expected, actual);
    if (!eq) message += $" (expected: {expected}, got: {actual})";
    AssertTrue(eq, message);
}

// ─── Resolve paths ──────────────────────────────────────────────────────────────

string scriptDir = Directory.GetCurrentDirectory();

// ─── Load the library under test via Roslyn scripting ───────────────────────────
// We compile CsvReportLib.cs into a scripting session so we can call its types.

string libSource = File.ReadAllText(Path.Combine(scriptDir, "CsvReportLib.cs"));

var scriptOptions = ScriptOptions.Default
    .AddReferences(typeof(object).Assembly, typeof(Enumerable).Assembly, typeof(File).Assembly)
    .AddImports("System", "System.Collections.Generic", "System.IO", "System.Linq");

var state = await CSharpScript.RunAsync(libSource, scriptOptions);

// Helper: continue the scripting session to call library methods
async Task<object?> Run(string code)
{
    state = await state.ContinueWithAsync(code);
    return state.ReturnValue;
}

